lines=open('compose.log',errors='replace').read().splitlines()
def ts(l):
    m=re.match(r'(\d\d:\d\d:\d\d)',l[11:19] if len(l)>19 else '')
    m=re.match(r'\d{4}-\d\d-\d\d (\d\d):(\d\d):(\d\d)',l)
    if not m: return None
    return int(m.group(1))*3600+int(m.group(2))*60+int(m.group(3))
lo=14*3600+0*60; hi=14*3600+42*60
post=collections.Counter(); other=[]
for i,l in enumerate(lines):
    t=ts(l)
    if t is None or not (lo<=t<=hi): continue
    if 'HTTP Request: POST' in l: post[(t//60)]+=1
    elif 'Connection error' in l: post[('CE',t//60)]+=1
    else: other.append((i+1,l[:150]))
